1	import { randomUUID } from "crypto";
2	import { readFileSync, writeFileSync, existsSync, mkdirSync } from "fs";
3	import { join } from "path";
4	import type { Graph, Node, Edge } from "../types.js";
5	
6	const DATA_PATH = join(process.env.HOME ?? "~", ".cartographer", "graph.json");
7	
8	function load(): Graph {
9	  if (!existsSync(DATA_PATH)) return { nodes: [], edges: [] };
10	  return JSON.parse(readFileSync(DATA_PATH, "utf8")) as Graph;
11	}
12	
13	function save(graph: Graph): void {
14	  const dir = join(process.env.HOME ?? "~", ".cartographer");
15	  mkdirSync(dir, { recursive: true });
16	  writeFileSync(DATA_PATH, JSON.stringify(graph, null, 2));
17	}
18	
19	export function addNode(title: string, body: string, tags: string[]): Node {
20	  const graph = load();
21	  const node: Node = {
22	    id: randomUUID(),
23	    title,
24	    body,
25	    tags,
26	    createdAt: new Date().toISOString(),
27	    updatedAt: new Date().toISOString(),
28	  };
29	  graph.nodes.push(node);
30	  save(graph);
31	  return node;
32	}
33	
34	export function link(fromTitle: string, toTitle: string, label?: string): Edge {
35	  const graph = load();
36	  const from = graph.nodes.find((n) => n.title === fromTitle);
37	  const to = graph.nodes.find((n) => n.title === toTitle);
38	  if (!from || !to) throw new Error(`Node not found`);
39	  const edge: Edge = { from: from.id, to: to.id, label, weight: 1 };
40	  graph.edges.push(edge);
41	  save(graph);
42	  return edge;
43	}
44	
45	export function removeNode(title: string): { node: Node; edgeCount: number } | null {
46	  const graph = load();
47	  const node = graph.nodes.find((n) => n.title === title);
48	  if (!node) return null;
49	  graph.nodes = graph.nodes.filter((n) => n.id !== node.id);
50	  const removedEdges = graph.edges.filter((e) => e.from === node.id || e.to === node.id);
51	  graph.edges = graph.edges.filter((e) => e.from !== node.id && e.to !== node.id);
52	  save(graph);
53	  return { node, edgeCount: removedEdges.length };
54	}
55	
56	export function exportMarkdown(): string {
57	  const graph = load();
58	  const lines: string[] = ["# Knowledge Map\n"];
59	  for (const node of graph.nodes) {
60	    lines.push(`## ${node.title}`);
61	    if (node.tags.length) lines.push(`*tags: ${node.tags.join(", ")}*\n`);
62	    lines.push(node.body);
63	    const outgoing = graph.edges.filter((e) => e.from === node.id);
64	    if (outgoing.length) {
65	      lines.push("\n**Links:**");
66	      for (const edge of outgoing) {
67	        const target = graph.nodes.find((n) => n.id === edge.to);
68	        if (target) lines.push(`- → [${target.title}]${edge.label ? ` *(${edge.label})*` : ""}`);
69	      }
70	    }
71	    lines.push("");
72	  }
73	  return lines.join("\n");
74	}
75	
76	export function graphStats(graph: Graph): { nodes: number; edges: number } {
77	  return { nodes: graph.nodes.length, edges: graph.edges.length };
78	}
79	
80	export function listNodeTitles(): string[] {
81	  const graph = load();
82	  return graph.nodes.map((n) => n.title);
83	}
84	
85	export function mostConnectedNode(graph: Graph): { node: Node | null; degree: number } {
86	  if (graph.edges.length === 0) {
87	    return { node: null, degree: 0 };
88	  }
89	
90	  const degreeMap = new Map<string, number>();
91	
92	  for (const edge of graph.edges) {
93	    // Bidirectional degree: each edge contributes +1 to both nodes
94	    // regardless of direction, counting both as connected
95	    degreeMap.set(edge.from, (degreeMap.get(edge.from) ?? 0) + 1);
96	    degreeMap.set(edge.to, (degreeMap.get(edge.to) ?? 0) + 1);
97	  }
98	
99	  let maxDegree = -1;
100	  let maxNode: Node | null = null;
101	
102	  for (const node of graph.nodes) {
103	    const degree = degreeMap.get(node.id) ?? 0;
104	    if (degree > maxDegree) {
105	      maxDegree = degree;
106	      maxNode = node;
107	    }
108	  }
109	
110	  return { node: maxNode, degree: maxDegree };
111	}
